export function getAllVocabulary() {
  return week27.days.flatMap((day, dayIndex) =>
    day.vocabulary.map((word, wordIndex) => ({
      ...word,
      id: `w27-d${dayIndex + 1}-${wordIndex}`,
      dayId: day.id,
      dayTitle: day.title,
    }))
  )
}
